import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    def distance(p1, p2):
        return np.linalg.norm(p1 - p2)

    # Initialize best choice
    best_node = None
    best_increase_in_distance = float('inf')

    for i, customer_pos in enumerate(unvisited_customers):
        potential_distance = distance(cur_truck_pos, customer_pos)
        max_dist_at_future = []  # Future total distances if this node is chosen

        for truck_pos in all_truck_pos:
            future_distances = [
                distance(truck_pos, unvisited_customers[idx])
                if idx != i else potential_distance
                for idx in range(len(unvisited_customers))
            ]
            if future_distances:  # Adding guard for empty list situations
                max_dist_at_future.append(min(future_distances))

        total_system_increase = sum(max_dist_at_future)

        # Check if this scenario gives a lower max distance increase overall
        if total_system_increase < best_increase_in_distance:
            best_increase_in_distance = total_system_increase
            best_node = i

    return best_node
